'use strict';

var callBound = require('call-bound');


var $register = callBound('FinalizationRegistry.prototype.register', true);


module.exports = $register
	? function isFinalizationRegistry(value) {
		if (!value || typeof value !== 'object') {
			return false;
		}
		try {
			
			$register(value, {}, null);
			return true;
		} catch (e) {
			return false;
		}
	}
	
	: function isFinalizationRegistry(value) { 
		return false;
	};
